// Version A
class OrderBookA {
  private orders: Order[] = [];
  add(order: Order) {
    if (this.orders.some(o => o.id === order.id)) throw new Error('dup');
    this.validate(order);
    this.orders.push(order);
  }
  findByUser(id: string) { return this.orders.filter(o => o.userId === id); }
}

